INSERT INTO posts (post_id, user_id, title, post_type, content, file_name, file_url, file_type, links, file_id, folder_id, created_at, updated_at) VALUES ('16', '1', 'Untitled Post', 'text', '<p>Hi Everyone,</p><p>We are pleased to announce that the MKM Facility has successfully uploaded a new collection of Knowledge Products to the KP Hub. These resources are now available for your reference and use.</p><p>📚 Newly Uploaded Knowledge Products:<br>1. Anti-virus Complete Scanning Tips<br>2. Browser CleanUp Guide<br>3. Disk Cleanup Guide<br>4. File Organization Tips<br>5. Hardware Defragmentation Guide<br>6. Windows Update Process</p><p>🎯 Purpose:<br>These comprehensive infographics have been developed to support anyone who wants to optimize their computers or laptops regularly. Whether you\'re a staff member or a general computer user, these easy-to-follow guides provide essential maintenance and optimization procedures to ensure improved system performance, security, and efficiency.</p><p>Thank you.</p>', NULL, NULL, NULL, '[{\"url\":\"https:\\/\\/drive.google.com\\/drive\\/folders\\/1B6t8qj_zo91rU-qI99y4_f9-v_prJ_8L\",\"label\":\"Link Here!\"}]', NULL, NULL, '2025-11-19 12:00:01', '2025-11-19 12:09:46');
